/// READ-USER-SEC-FILE
fn p_read_user_sec_file(state: &mut ProgramState) {
    // EXEC CICS READ 
    state.cics.execute("READ", &[("DATASET", Some("_unknown")), ("WS-USRSEC-FILE", Some("_unknown")), ("INTO", Some("_unknown")), ("SEC-USER-DATA", Some("_unknown")), ("LENGTH", Some("_unknown")), ("LENGTH", Some("OF")), ("SEC-USER-DATA", Some("_unknown")), ("RIDFLD", Some("_unknown")), ("SEC-USR-ID", Some("_unknown")), ("KEYLENGTH", Some("_unknown")), ("LENGTH", Some("OF")), ("SEC-USR-ID", Some("_unknown")), ("UPDATE", None), ("RESP", Some("_unknown")), ("WS-RESP-CD", Some("_unknown")), ("RESP2", Some("_unknown")), ("WS-REAS-CD", Some("_unknown"))]);
    match state.ws_variables.ws_resp_cd {
        _ => {
            state.ws_variables.ws_message = "Press PF5 key to delete this user ...".into();
            state.cousr3ao.errmsgc = FixedString::copy_from(&state.dfhneutr);
            p_send_usrdel_screen(state);
        }
        _ => {
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "User ID NOT found...".into();
            state.cousr3ai.usridinl = -1 as i32;
            p_send_usrdel_screen(state);
        }
        _ => {
            println!("{}{}{}{}", "RESP:", state.ws_variables.ws_resp_cd, "REAS:", state.ws_variables.ws_reas_cd);
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "Unable to lookup User...".into();
            state.cousr3ai.fnamel = -1 as i32;
            p_send_usrdel_screen(state);
        }
    }
}

/// DELETE-USER-SEC-FILE
fn p_delete_user_sec_file(state: &mut ProgramState) {
    // EXEC CICS DELETE 
    state.cics.execute("DELETE", &[("DATASET", Some("_unknown")), ("WS-USRSEC-FILE", Some("_unknown")), ("RESP", Some("_unknown")), ("WS-RESP-CD", Some("_unknown")), ("RESP2", Some("_unknown")), ("WS-REAS-CD", Some("_unknown"))]);
    match state.ws_variables.ws_resp_cd {
        _ => {
            p_initialize_all_fields(state);
            state.ws_variables.ws_message = FixedString::spaces();
            state.cousr3ao.errmsgc = FixedString::copy_from(&state.dfhgreen);
            {
                let mut _str_ptr: usize = 1;
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, "User ".as_bytes());
                let _bytes_tmp = state.sec_user_data.sec_usr_id.to_string(); let _src = string_delimited(_bytes_tmp.as_bytes(), b" ");
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, _src);
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, " has been deleted ...".as_bytes());
            }
            p_send_usrdel_screen(state);
        }
        _ => {
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "User ID NOT found...".into();
            state.cousr3ai.usridinl = -1 as i32;
            p_send_usrdel_screen(state);
        }
        _ => {
            println!("{}{}{}{}", "RESP:", state.ws_variables.ws_resp_cd, "REAS:", state.ws_variables.ws_reas_cd);
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "Unable to Update User...".into();
            state.cousr3ai.fnamel = -1 as i32;
            p_send_usrdel_screen(state);
        }
    }
}

/// CLEAR-CURRENT-SCREEN
fn p_clear_current_screen(state: &mut ProgramState) {
    p_initialize_all_fields(state);
    p_send_usrdel_screen(state);
}

/// INITIALIZE-ALL-FIELDS
fn p_initialize_all_fields(state: &mut ProgramState) {
    state.cousr3ai.usridinl = -1 as i32;
    state.cousr3ai.usridini = FixedString::spaces();
    state.cousr3ai.fnamei = FixedString::spaces();
    state.cousr3ai.lnamei = FixedString::spaces();
    state.cousr3ai.usrtypei = FixedString::spaces();
    state.ws_variables.ws_message = FixedString::spaces();
}

